package model; public class Member{private int id;private String account,password,name,email,phone,role; public Member(){} public Member(int id,String account,String password,String name,String email,String phone,String role){this.id=id;this.account=account;this.password=password;this.name=name;this.email=email;this.phone=phone;this.role=role;} public int getId(){return id;} public void setId(int id){this.id=id;} public String getAccount(){return account;} public void setAccount(String a){account=a;} public String getPassword(){return password;} public void setPassword(String p){password=p;} public String getName(){return name;} public void setName(String n){name=n;} public String getEmail(){return email;} public void setEmail(String e){email=e;} public String getPhone(){return phone;} public void setPhone(String p){phone=p;} public String getRole(){return role;} public void setRole(String r){role=r;} }
